        // Tìm sản phẩm...
        if (product == null) {
            return ResponseEntity.notFound().build(); // HTTP 404
        }
        return ResponseEntity.ok(product); // HTTP 200
    }

    // 3. POST: Đăng bán sản phẩm mới
    @PostMapping
    public ResponseEntity<Product> createProduct(@RequestBody ProductDTO productDTO) {
